        // Simulating user input
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        // Sanitize and escape user input using OWASP Java Encoder library
        String sanitizedInput = Encode.forHtml(userInput);

        // Printing the output to a web page with sanitized user input
        try {
            PrintWriter writer = new PrintWriter("output.html", "UTF-8");
            writer.println("<html><body>");
            writer.println("Welcome, " + sanitizedInput);
            writer.println("</body></html>");
            writer.close();

